var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_B","text":{"KOREA":"…누구야 , 그 의뢰인이라는 게?","JPN":"……で？　誰なんだ、その依頼人って。","ENG":"...So who's this \\"client,\\" anyway?","TWN":"……那個所謂的委託人，是誰啊？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_A","text":{"KOREA":"나야 모르지. 샤레이드 장로회에서 왔다는데… 아마 사이비일 거야. 말하는 투도 정상은 아니었으니.","JPN":"知らねぇよ。シャレード支部長老会から来たらしいが……どうせインチキだろう。話し方もおかしかったし。","ENG":"No idea. Says he's from the Charade Council... Probably some kind of cultist. The way he talked wasn't normal.","TWN":"我哪知道。他說來自查雷德長老會……大概是邪教吧，說話方式就不太正常。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_B","text":{"KOREA":"우리 할머니도 교회 다니시는데, 그런 사이비 놈들이 종교인들 평판을 다 깎아먹는단 말이지.","JPN":"うちのばあちゃんも教会通ってるけどよ、ああいうインチキどもがいるから信仰者のイメージが悪くなるんだよな。","ENG":"My grandma goes to church, you know. Guys like that ruin the reputation of real believers.","TWN":"我奶奶也有去教會，那些邪教的人最會敗壞信徒的名聲了。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_B","text":{"KOREA":"그런 놈이 왜 거금을 주면서 우리한테 이딴 일을 맡기는 거람?","JPN":"で、そいつがなんで巨額を払ってまで俺たちにこんな仕事を依頼したんだ？","ENG":"So why would a creep like that pay us a fortune to do this kind of job?","TWN":"可是那種人為什麼要花大錢，請我們做這種事？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_A","text":{"KOREA":"미친놈들을 이해하려 하지 마.","JPN":"頭いかれた連中だろ。理解しようとするだけ損だぜ。","ENG":"Don't try to understand lunatics.","TWN":"別試著去理解瘋子。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_A","text":{"KOREA":"마젤란 예언회가 큰 돈 주면서 형님한테 살아있는 침식체를 잡아 달라던 거 기억해? 알고 보니 그걸 길들이려고 했었단 말이지.","JPN":"マジェラン預言会が金を積んで兄貴に侵食体の生け捕りを依頼したのを覚えてるか？　後で知ったんだが、あれは侵食体を手懐けるつもりだったんだと。","ENG":"Remember when Magellan's Prediction Society paid the boss big money to capture a C.O. alive? Turned out they were trying to tame it.","TWN":"你還記得以前麥哲倫預言會花大錢，拜託大哥抓一隻活體侵蝕體嗎？結果原來是打算圈養。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_B","text":{"KOREA":"그런 부류랑은 엮이기 싫어. 결국 그놈들한테 넘긴 침식체가 도시에서 날뛰는 바람에 우리 목숨까지 위험해졌었다고.","JPN":"そういう類とはそもそも関わりたくないんだよ。結局そいつらに渡した侵食体が都市で暴れちまって、俺たちの命まで危険に晒されたじゃないか。","ENG":"I don't want anything to do with that sort. Handing that thing over nearly got us killed when it went berserk in the city.","TWN":"我可不想再跟那種人扯上關係。最後那隻交給他們的侵蝕體在城市裡暴走，害我們差點賠上小命。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_B","text":{"KOREA":"이번에도 우리가 만들어준 이걸로 우리가 피해를 볼지 어떻게 알아?","JPN":"今回も俺たちが作ったこれのせいで、被害がこっちにまで及ばないとも限らないだろう？","ENG":"How do we know this thing we made won't come back to bite us again?","TWN":"誰知道這次會不會也用我們做出來的東西反咬我們一口？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_A","text":{"KOREA":"별 수 있나. 우리 일이 돈 받으면 시키는 대로 하는 건데.","JPN":"仕方ないじゃないか。金をもらったら言われた通りにするのが俺たちの仕事だし。","ENG":"What choice do we have? We get paid, we do the job.","TWN":"但又能怎樣？我們的工作不就是收錢辦事嗎？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_B","text":{"KOREA":"…말하니까 오네. 그놈이야.","JPN":"……噂をすればだ。来たぞ。","ENG":"...Speak of the devil. That's him.","TWN":"……說著說著，人就來了。就是那傢伙。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_A","text":{"KOREA":"신원 체크는 생략합시다. 우리 고객님은 얼굴을 안 까셔도 아우라가 다르니까.","JPN":"身元チェックは省略しましょうかね。お客様は顔を隠していてもオーラが違うようだ。","ENG":"Let's skip the background check. Our client doesn't need to show his face. His aura says enough.","TWN":"身分確認就免了。我們的客人就算不露臉，氣場也完全不一樣。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_A","text":{"KOREA":"여기, 말한 물건이요.","JPN":"……頼まれたブツだ。","ENG":"Here. The item you asked for.","TWN":"這是您要的東西。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_A","text":{"KOREA":"요청받은 대로 전자장비 일절 안 쓰고 우리가 수기로 그린 지도야.","JPN":"言われた通り、地図は電子装備を一切使わず手書きで作った。","ENG":"Just like you requested, no electronic devices. We drew the map by hand.","TWN":"完全依照您的要求，沒有使用任何電子設備、完全手繪的地圖。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_A","text":{"KOREA":"모든 CCTV위치부터 경찰들 순찰 도는 루트, 암거래상들이 쓰는 뒷길까지 구획 별로 전부 기록해 뒀지.","JPN":"すべての防犯カメラの位置から、警察の見回りルート、闇商人が使う裏道まで、区画ごとに記録してある。","ENG":"Every CCTV location, police patrol routes, even the back alleys used by black-market dealers. It's all marked out by sector.","TWN":"從所有監視器的位置、警方巡邏路線，到黑市商人使用的巷弄，全都依區域標記清楚了。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_A","text":{"KOREA":"그럼… 물건은 넘겼으니까. 우린 이만 가보겠수다.","JPN":"じゃあ……ブツは確かに渡したから、俺たちは帰らせてもらうよ。","ENG":"Well then... We've delivered the goods. We'll be on our way.","TWN":"那麼……東西也交付給您了，我們就先告辭了。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_B","text":{"KOREA":"당신, 우리 그라운드원에 한동안 있을 거지? 안 그럼 이런 지도를 갖고 있을 이유가 없잖아.","JPN":"あんた、しばらくグラウンド・ワンにいるつもりなんだろ？　こんな地図を頼んだってことは。","ENG":"You're planning to stick around Ground One for a while, right? Otherwise, there'd be no reason to have a map like that.","TWN":"你，會在我們G1待一段時間吧？不然也沒必要拿這種地圖啊。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_B","text":{"KOREA":"경고하는데, 조용히 다니는 게 신상에 좋을 거야.","JPN":"言っておくけど、騒ぎは立てないほうが身のためだぞ。","ENG":"I'm warning you. Keeping a low profile would be best for you.","TWN":"我先警告你，低調行事對你比較好。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_B","text":{"KOREA":"우리 형님이 사이비한테 거하게 통수를 맞으신 적이 있어서 사이비라면 아주 치를 떠시거든?","JPN":"うちの兄貴、インチキ宗教に派手に裏切られたことがあってさ、インチキが大嫌いなんだよ。","ENG":"Our boss really hates cultists. Got burned bad by one before.","TWN":"我們大哥以前被邪教狠狠背叛過一次，只要聽到邪教兩個字就會暴怒。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_A","text":{"KOREA":"방금… 고개 끄덕이지 않았어?","JPN":"今……頷いてなかったか？","ENG":"Did he... just nod?","TWN":"剛剛……是不是點頭了？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_A","text":{"KOREA":"이만하면 알아들은 거 같은데… 이제 가자.","JPN":"それだけ言えば十分じゃないか？　もう行こうぜ。","ENG":"Looks like he got the message. Let's go.","TWN":"看來是聽懂了……走吧。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_B","text":{"KOREA":"어이, 대답 안 해?","JPN":"おい、ちゃんと返事しないか？","ENG":"Hey. Aren't you going to answer?","TWN":"喂，你怎麼不回話？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_B","text":{"KOREA":"남의 구역에 왔으면 예의범절을 지켜야지. 그 거지 같은 가면부터 벗으…!","JPN":"人の縄張りに来たら礼儀をわきまえろってんだ。まずそのクソみたいな仮面から外……！","ENG":"You come into someone else's territory, you show some manners. Start by taking off that damn mask–!","TWN":"到了別人的地盤就要懂禮數，先把那個破面具摘……！"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_B","text":{"KOREA":"으, 으아악!","JPN":"う、うわああっ！","ENG":"W-whoa!","TWN":"呃、啊啊啊啊！"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_A","text":{"KOREA":"미친… 다 썩었잖아…?!","JPN":"何だあれ……全部腐ってる……！？","ENG":"What the heck...?! It's completely rotten...?!","TWN":"見鬼……全都腐爛了……？！"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_LAUGH"},"R":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"…비밀 규율에 따라…","JPN":"……秘密の規律に従い……","ENG":"...By the hidden ordinance...","TWN":"……依照祕密戒律……"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_LAUGH"},"R":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"…죄인을 일용함을, 허하소서…","JPN":"……罪人を食すことを許したまえ……","ENG":"...Grant me leave to consume the sinners of this day...","TWN":"……允許將罪人，作為日用之糧……"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_DESPAIR"},"R":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"}}}}]`);export{e as default};